let dimensionData = "VALUE,";
queries.fetchConfigDetails.data?.Dimensions?.forEach((val, idx) => {
  dimensionData += val.dimension_name;
  if(idx !== queries.fetchConfigDetails.data.Dimensions.length)
  dimensionData += ",";
});
let formattedData = parameters.type === "csv" ? dimensionData : dimensionData.replace(/,/g, '\t');

const blob = new Blob([formattedData], { type: parameters.type === "csv" ? 'text/csv;charset=utf-8;' : 'text/tab-separated-values;charset=utf-8;'});
const url = URL.createObjectURL(blob);
const link = document.createElement('a');
link.href = url;
link.download = `${ page.variables.selectedConfig}${parameters.type === "csv"? ".csv": ".tsv"}`; // Name of the file to be downloaded
document.body.appendChild(link);
link.click();
document.body.removeChild(link);

